inlineStyles:
:root {
  --bg: oklch(98% 0.005 60);
  --text: oklch(18% 0.01 60);
  --text2: oklch(45% 0.01 60);
  --text3: oklch(62% 0.01 60);
  --accent: oklch(45% 0.12 30);
  --border: oklch(90% 0.005 60);
  --note-bg: oklch(96% 0.008 60);
  --serif: 'Noto Serif SC', 'Newsreader', Georgia, serif;
  --sans: 'Source Sans 3', -apple-system, system-ui, sans-serif;
}
* { margin: 0; padding: 0; box-sizing: border-box; }
html { scroll-behavior: smooth; }
body {
  font-family: var(--sans);
  background: var(--bg);
  color: var(--text);
  line-height: 1.85;
  -webkit-font-smoothing: antialiased;
  padding-bottom: env(safe-area-inset-bottom);
}
::selection { background: oklch(90% 0.08 30); }
.progress { position: fixed; top: 0; left: 0; height: 2px; background: var(--accent); z-index: 100; width: 0; }
.header {
  max-width: 640px;
  margin: 0 auto;
  padding: clamp(48px, 10vw, 100px) clamp(20px, 5vw, 48px) 0;
}
.header .back {
  font-size: 0.8125rem;
  color: var(--text3);
  text-decoration: none;
  letter-spacing: 0.02em;
}
.header .back:hover { color: var(--text); }
.header h1 {
  font-family: var(--serif);
  font-size: clamp(1.625rem, 4vw, 2.25rem);
  font-weight: 700;
  line-height: 1.25;
  margin-top: 24px;
  letter-spacing: -0.02em;
}
.header .subtitle {
  font-size: 1rem;
  color: var(--text2);
  margin-top: 12px;
  line-height: 1.6;
  font-weight: 300;
}
.header .meta {
  font-size: 0.8125rem;
  color: var(--text3);
  margin-top: 20px;
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
}
.tldr {
  max-width: 640px;
  margin: 48px auto 0;
  padding: 0 clamp(20px, 5vw, 48px);
}
.tldr-box {
  border-top: 2px solid var(--text);
  padding-top: 20px;
}
.tldr-label {
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text3);
  margin-bottom: 10px;
}
.tldr-box p {
  font-size: 0.9375rem;
  line-height: 1.8;
}
.nums {
  display: flex;
  gap: clamp(16px, 4vw, 32px);
  margin-top: 20px;
  flex-wrap: wrap;
}
.nums .n { font-family: var(--serif); font-size: 1.5rem; font-weight: 700; }
.nums .d { font-size: 0.75rem; color: var(--text3); }
.toc {
  max-width: 640px;
  margin: 48px auto 0;
  padding: 0 clamp(20px, 5vw, 48px);
}
.toc-label {
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--text3);
  margin-bottom: 12px;
}
.toc ol {
  list-style: none;
  columns: 2;
  column-gap: 32px;
}
.toc li { break-inside: avoid; margin-bottom: 5px; }
.toc a {
  font-size: 0.875rem;
  color: var(--text2);
  text-decoration: none;
  line-height: 1.5;
  transition: color 0.15s;
}
.toc a:hover { color: var(--text); }
@media (max-width: 520px) { .toc ol { columns: 1; } }
.article {
  max-width: 640px;
  margin: 56px auto 0;
  padding: 0 clamp(20px, 5vw, 48px);
}
.ch { margin-bottom: 48px; }
.ch-label {
  font-size: 0.75rem;
  color: var(--text3);
  letter-spacing: 0.05em;
  margin-bottom: 4px;
}
.ch h2 {
  font-family: var(--serif);
  font-size: clamp(1.125rem, 2.5vw, 1.375rem);
  font-weight: 600;
  line-height: 1.35;
  margin-bottom: 16px;
}
.ch p {
  font-size: 0.9375rem;
  line-height: 1.9;
  margin-bottom: 12px;
}
.ch p strong { font-weight: 600; }
.ch blockquote {
  margin: 20px 0;
  padding: 0 0 0 20px;
  border-left: 2px solid var(--border);
}
.ch blockquote p {
  font-family: var(--serif);
  font-size: 0.9375rem;
  font-style: italic;
  color: var(--text2);
  margin: 0;
}
.ch blockquote .attr {
  font-family: var(--sans);
  font-size: 0.8125rem;
  color: var(--text3);
  font-style: normal;
  margin-top: 4px;
}
.ed {
  margin: 16px 0;
  padding: 16px 20px;
  background: var(--note-bg);
  border-radius: 2px;
  font-size: 0.8125rem;
  line-height: 1.75;
  color: var(--text2);
}
.ed .tag {
  font-weight: 600;
  font-size: 0.6875rem;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--text3);
  margin-bottom: 4px;
}
.sep {
  width: 24px;
  height: 1px;
  background: var(--border);
  margin: 40px 0;
}
.tensions {
  max-width: 640px;
  margin: 64px auto 0;
  padding: 0 clamp(20px, 5vw, 48px);
}
.tensions > h2 {
  font-family: var(--serif);
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: 28px;
}
.ti { margin-bottom: 28px; }
.ti h3 {
  font-size: 0.9375rem;
  font-weight: 600;
  margin-bottom: 6px;
}
.ti p {
  font-size: 0.875rem;
  line-height: 1.85;
  color: var(--text2);
}
.footer {
  max-width: 640px;
  margin: 80px auto 0;
  padding: 24px clamp(20px, 5vw, 48px) 48px;
  border-top: 1px solid var(--border);
  font-size: 0.8125rem;
  color: var(--text3);
}
.footer a { color: var(--text2); text-decoration: none; }
